#include <stdio.h>
#include <stdbool.h>
#define MAX_N 100000

// Define the structure for a tree node
typedef struct Node {
    int value;
    int numChildren;
    int* children;
} Node;

// Function to create a new node
Node* createNode(int value) {
    Node* node = (Node*) malloc(sizeof(Node));
    node->value = value;
    node->numChildren = 0;
    node->children = NULL;
    return node;
}

// Function to add a child to a node
void addChild(Node* node, Node* child) {
    node->numChildren++;
    node->children = (Node**) realloc(node->children, node->numChildren * sizeof(Node*));
    node->children[node->numChildren - 1] = child;
}

// Function to perform DFS and check if there's a path with the target sum
bool dfs(Node* node, int targetSum, int currentSum) {
    if (node == NULL) return false;
    currentSum += node->value;
    if (node->numChildren == 0 && currentSum == targetSum) return true;
    for (int i = 0; i < node->numChildren; i++) {
        if (dfs(node->children[i], targetSum, currentSum)) return true;
    }
    return false;
}

int main() {
    int N, targetSum;
    scanf("%d %d", &N, &targetSum);
    Node** nodes = (Node**) malloc(N * sizeof(Node*));
    for (int i = 0; i < N; i++) {
        nodes[i] = createNode(i + 1);
    }
    for (int i = 0; i < N - 1; i++) {
        int u, v;
        scanf("%d %d", &u, &v);
        u--; v--;
        addChild(nodes[u], nodes[v]);
        addChild(nodes[v], nodes[u]);
    }
    if (dfs(nodes[0], targetSum, 0)) {
        printf("YES\n");
    } else {
        printf("NO\n");
    }
    return 0;
}

