#include <iostream>
#include <vector>
using namespace std;

// Define the structure for a tree node
struct Node {
    int value;
    vector<int> children;
};

// Function to perform DFS and check if there's a path with the target sum
bool dfs(const vector<Node>& nodes, int targetSum, int currentSum, int nodeIndex) {
    if (nodeIndex < 0 || nodeIndex >= nodes.size()) return false;
    currentSum += nodes[nodeIndex].value;
    if (nodes[nodeIndex].children.empty() && currentSum == targetSum) return true;
    for (int childIndex : nodes[nodeIndex].children) {
        if (dfs(nodes, targetSum, currentSum, childIndex)) return true;
    }
    return false;
}

int main() {
    int N, targetSum;
    cin >> N >> targetSum;
    vector<Node> nodes(N);
    for (int i = 0; i < N; i++) {
        nodes[i].value = i + 1;
    }
    for (int i = 0; i < N - 1; i++) {
        int u, v;
        cin >> u >> v;
        u--; v--;
        nodes[u].children.push_back(v);
        nodes[v].children.push_back(u);
    }
    if (dfs(nodes, targetSum, 0, 0)) {
        cout << "YES" << endl;
    } else {
        cout << "NO" << endl;
    }
    return 0;
}

