import java.util.ArrayList;
import java.util.List;
import java.util.Scanner;

// Define the structure for a tree node
class Node {
    int value;
    List<Node> children;

    public Node(int value) {
        this.value = value;
        this.children = new ArrayList<>();
    }
}

public class Main {
    // Function to perform DFS and check if there's a path with the target sum
    public static boolean dfs(Node node, int targetSum, int currentSum) {
        if (node == null) return false;
        currentSum += node.value;
        if (node.children.isEmpty() && currentSum == targetSum) return true;
        for (Node child : node.children) {
            if (dfs(child, targetSum, currentSum)) return true;
        }
        return false;
    }

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int N = scanner.nextInt();
        int targetSum = scanner.nextInt();
        Node[] nodes = new Node[N];
        for (int i = 0; i < N; i++) {
            nodes[i] = new Node(i + 1);
        }
        for (int i = 0; i < N - 1; i++) {
            int u = scanner.nextInt() - 1;
            int v = scanner.nextInt() - 1;
            nodes[u].children.add(nodes[v]);
            nodes[v].children.add(nodes[u]);
        }
        if (dfs(nodes[0], targetSum, 0)) {
            System.out.println("YES");
        } else {
            System.out.println("NO");
        }
    }
}

