const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;

// Define the structure for a tree node
class Node {
    constructor(value) {
        this.value = value;
        this.children = [];
    }
}

// Function to perform DFS and check if there's a path with the target sum
function dfs(node, targetSum, currentSum) {
    if (node === null) return false;
    currentSum += node.value;
    if (node.children.length === 0 && currentSum === targetSum) return true;
    for (const child of node.children) {
        if (dfs(child, targetSum, currentSum)) return true;
    }
    return false;
}

// Read input
const [N, targetSum] = input[idx++].split(' ').map(Number);

// Create nodes
const nodes = Array(N).fill(0).map((_, i) => new Node(i + 1));

// Read edges and add children
for (let i = 0; i < N - 1; i++) {
    const [u, v] = input[idx++].split(' ').map(Number);
    nodes[u - 1].children.push(nodes[v - 1]);
    nodes[v - 1].children.push(nodes[u - 1]);
}

// Perform DFS and print result
if (dfs(nodes[0], targetSum, 0)) {
    console.log('YES');
} else {
    console.log('NO');
}
